const express = require('express');
const app = express();
const mysql = require('mysql2')

const port = 3001; //the port on which you want the server to run
app.listen(port, () => {
    console.log(`Server started at http://localhost:${port}`);
});


//this is where your code should go
app.get('/products/:name', (req, res) => {
    const connection = mysql.createConnection({
        host: 'localhost',
        user: 'root',
        password: '', //enter the password for the root user of MySQL here
        database: 'test'
    });

    let queryString = `select * from products where name like '%${req.params.name}%';`;

    connection.query(queryString, (err, results) => {

        if (!err) {
            res.send(results);
        } else {
            console.log('There was an error in retrieving the data', err);
        }
    });
});

